import React, { useState } from 'react';
import { CheckCircle, Clock, CreditCard, ShieldCheck, Download, Calendar } from 'lucide-react';
import { Card, Button, Badge } from '../../components/ui/UIComponents';
import { Tenant, Property, Payment, PaymentStatus } from '../../types';
import { LineChart, Line, XAxis, Tooltip, ResponsiveContainer } from 'recharts';

interface TenantDashboardProps {
  tenant: Tenant;
  property: Property;
  payments: Payment[];
  onPayRent: (amount: number) => void;
}

export const TenantDashboard: React.FC<TenantDashboardProps> = ({ tenant, property, payments, onPayRent }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  // Determine if rent is due for current month (simulated logic)
  // In a real app, compare current date with last payment date
  const isRentPaidForThisMonth = payments.some(p => {
    const paymentDate = new Date(p.date);
    const now = new Date();
    return paymentDate.getMonth() === now.getMonth() && paymentDate.getFullYear() === now.getFullYear();
  });

  const nextDueDate = new Date();
  if (isRentPaidForThisMonth) {
     nextDueDate.setMonth(nextDueDate.getMonth() + 1);
  }
  nextDueDate.setDate(property.dueDate);

  const handlePayment = () => {
    setIsProcessing(true);
    // Simulate gateway
    setTimeout(() => {
      setIsProcessing(false);
      setShowSuccess(true);
      onPayRent(property.rentAmount);

      // Auto-hide success after a few seconds
      setTimeout(() => setShowSuccess(false), 5000);
    }, 2000);
  };

  const creditHistoryData = [
    { month: 'Jan', score: 705 },
    { month: 'Feb', score: 710 },
    { month: 'Mar', score: tenant.creditScore },
  ];

  return (
    <div className="space-y-6">

      {/* SUCCESS MODAL OVERLAY */}
      {showSuccess && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-in fade-in duration-300">
          <Card className="p-8 max-w-sm w-full text-center relative animate-in zoom-in-95 duration-300">
             <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
               <CheckCircle className="w-8 h-8 text-green-600" />
             </div>
             <h2 className="text-xl font-bold text-gray-900 mb-2">Payment Successful!</h2>
             <p className="text-gray-500 mb-6">Your rent of ${property.rentAmount} has been transferred to escrow. Receipt generated.</p>

             <div className="bg-indigo-50 p-3 rounded-lg flex items-center justify-center gap-2 mb-6">
                <ShieldCheck className="w-5 h-5 text-indigo-600" />
                <span className="font-semibold text-indigo-700">+10 Credit Points</span>
             </div>

             <Button fullWidth onClick={() => setShowSuccess(false)}>
               Done
             </Button>
          </Card>
        </div>
      )}

      {/* HEADER */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Welcome back, {tenant.name.split(' ')[0]}</h1>
        <p className="text-gray-500">Your rental health is looking good.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* CREDIT SCORE CARD - HERO */}
        <Card className="p-6 md:col-span-2 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50 rounded-full -mr-16 -mt-16 opacity-50 pointer-events-none" />

          <div className="flex justify-between items-start relative z-10">
            <div>
              <h3 className="text-lg font-medium text-gray-900">Rental Credit Score</h3>
              <p className="text-sm text-gray-500">Powered by TrustRent AI</p>
            </div>
            <Badge variant="success">Excellent</Badge>
          </div>

          <div className="flex items-end gap-4 mt-6 relative z-10">
            <span className="text-6xl font-black text-indigo-600 tracking-tighter">
              {tenant.creditScore}
            </span>
            <span className="text-sm text-gray-500 mb-2">/ 900</span>
          </div>

          <div className="h-32 mt-4 -ml-2">
             <ResponsiveContainer width="100%" height="100%">
               <LineChart data={creditHistoryData}>
                 <XAxis dataKey="month" axisLine={false} tickLine={false} />
