import React, { useState, useEffect } from 'react';
import { Login } from './pages/Login';
import { Layout } from './components/Layout';
import { LandlordDashboard } from './pages/landlord/LandlordDashboard';
import { Properties } from './pages/landlord/Properties';
import { TenantDashboard } from './pages/tenant/TenantDashboard';
import { Chatbot } from './components/Chatbot';
import { User, UserRole, Tenant, Property, Payment, PaymentStatus } from './types';
import { MOCK_LANDLORD, MOCK_TENANT, PROPERTIES, MOCK_PAYMENTS } from './constants';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [currentPage, setCurrentPage] = useState('dashboard');

  // App State (Hoisted for interactivity)
  const [properties, setProperties] = useState<Property[]>(PROPERTIES);
  const [payments, setPayments] = useState<Payment[]>(MOCK_PAYMENTS);
  const [currentTenant, setCurrentTenant] = useState<Tenant>(MOCK_TENANT);

  // Tenant Logic: Pay Rent
  const handlePayRent = (amount: number) => {
    // 1. Create new payment
    const newPayment: Payment = {
      id: `pay_${Date.now()}`,
      propertyId: currentTenant.currentPropertyId,
      tenantId: currentTenant.id,
      amount: amount,
      date: new Date().toISOString().split('T')[0],
      status: PaymentStatus.PAID,
      isLate: false
    };

    setPayments([newPayment, ...payments]);

    // 2. Update Credit Score (+15 points for demo effect)
    setCurrentTenant(prev => ({
      ...prev,
      creditScore: Math.min(900, prev.creditScore + 15)
    }));
  };

  // Landlord Logic: View Property (simple navigation)
  const handleSelectProperty = (id: string) => {
    // For this prototype, we just log it or could switch to a details page
    // Simulating "Details Page" by just staying on properties for now 
    // or we could add a specific page state. 
    // Let's keep it simple: The dashboard shows aggregate, Properties shows list.
    alert(`Navigating to details for property ${id} (Implemented in Dashboard View)`);
  };

  const handleLogin = (role: UserRole) => {
    if (role === UserRole.LANDLORD) {
      setUser(MOCK_LANDLORD);
    } else {
      setUser(currentTenant);
    }
    setCurrentPage('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('dashboard');
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  // Prepare Context for AI
  const aiContext = user.role === UserRole.LANDLORD 
    ? { properties, recentRevenue: 9500, tenantIssues: 0 }
    : { tenantProfile: currentTenant, property: properties.find(p => p.id === currentTenant.currentPropertyId), paymentHistory: payments };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      activePage={currentPage}
      onNavigate={setCurrentPage}
    >
      {/* Dynamic Page Rendering */}
      {user.role === UserRole.LANDLORD && (
        <>
          {currentPage === 'dashboard' && (
            <LandlordDashboard 
              properties={properties} 
              onNavigate={setCurrentPage} 
            />
          )}
          {currentPage === 'properties' && (
            <Properties 
              properties={properties} 
              onSelectProperty={handleSelectProperty} 
            />
          )}
           {currentPage === 'payments' && (
             <div className="flex items-center justify-center h-64 text-gray-400">
               Payment Management Module (Coming Soon)
             </div>
           )}
        </>
      )}

      {user.role === UserRole.TENANT && (
        <>
          {currentPage === 'dashboard' && (
            <TenantDashboard 
              tenant={currentTenant}
              property={properties.find(p => p.id === currentTenant.currentPropertyId)!}
              payments={payments}
              onPayRent={handlePayRent}
            />
          )}
          {currentPage === 'payments' && (
             <div className="flex items-center justify-center h-64 text-gray-400">
               Full History View (See Dashboard for summary)
             </div>
           )}
        </>
      )}

      {/* AI Assistant */}
      <Chatbot userRole={user.role} contextData={aiContext} />
    </Layout>
  );
}

