                   <h3 className="text-lg font-bold text-gray-900">{complaint.subject}</h3>
                   <p className="text-gray-600 mt-2">{complaint.description}</p>
                 </div>

                 <div className="flex items-center">
                    {complaint.status === 'Open' && (
                      <Button onClick={() => onResolve(complaint.id)} variant="outline" size="sm">
                        Mark as Resolved
                      </Button>
                    )}
                 </div>
               </div>
            </Card>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Download, Search, Filter } from 'lucide-react';
import { Card, Badge, Button } from '../../components/ui/UIComponents';
import { Payment, Property, Tenant } from '../../types';
import { generateInvoicePDF } from '../../utils/invoiceGenerator';

interface PaymentHistoryProps {
  properties: Property[];
  payments: Payment[];
  tenants: Tenant[]; // In a real app this would be a map or fetch call
}

export const PaymentHistory: React.FC<PaymentHistoryProps> = ({ properties, payments, tenants }) => {
  const [selectedPropertyId, setSelectedPropertyId] = useState<string>('all');

  // Filter payments based on selection
  const filteredPayments = selectedPropertyId === 'all' 
    ? payments 
    : payments.filter(p => p.propertyId === selectedPropertyId);

  // Helper to get tenant name (simplified for prototype)
  const getTenantName = (id: string) => {
    const t = tenants.find(tenant => tenant.id === id);
    return t ? t.name : 'Unknown Tenant';
  };

  // Helper to get property address
  const getPropertyAddress = (id: string) => {
    const p = properties.find(prop => prop.id === id);
    return p ? p.address : 'Unknown Property';
  };

  const handleDownload = (payment: Payment) => {
    const property = properties.find(p => p.id === payment.propertyId);
    const tenant = tenants.find(t => t.id === payment.tenantId);

    if (property && tenant) {
      generateInvoicePDF(payment, property, tenant);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Payment Archive</h1>
          <p className="text-gray-500">View and download past invoices</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <select 
              className="w-full appearance-none pl-4 pr-10 py-2.5 bg-white border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              value={selectedPropertyId}
              onChange={(e) => setSelectedPropertyId(e.target.value)}
            >
              <option value="all">All Properties</option>
              {properties.map(p => (
                <option key={p.id} value={p.id}>{p.address}</option>
              ))}
            </select>
            <div className="absolute right-3 top-3 pointer-events-none text-gray-500">
               <Filter className="w-4 h-4" />
            </div>
          </div>
        </div>
      </div>

      <Card className="overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-4 font-medium text-gray-500">Date</th>
                <th className="px-6 py-4 font-medium text-gray-500">Property</th>
                <th className="px-6 py-4 font-medium text-gray-500">Tenant</th>
                <th className="px-6 py-4 font-medium text-gray-500">Amount</th>
                <th className="px-6 py-4 font-medium text-gray-500">Status</th>
                <th className="px-6 py-4 font-medium text-gray-500 text-right">Invoice</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {filteredPayments.length === 0 ? (
                <tr>
                   <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                     No payment records found for this selection.
                   </td>
                </tr>
              ) : (
                filteredPayments.map((payment) => (
                  <tr key={payment.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 text-gray-900">{payment.date}</td>
                    <td className="px-6 py-4 text-gray-900 font-medium">{getPropertyAddress(payment.propertyId)}</td>
                    <td className="px-6 py-4 text-gray-500">{getTenantName(payment.tenantId)}</td>
                    <td className="px-6 py-4 font-medium text-gray-900">${payment.amount}</td>
                    <td className="px-6 py-4">
                      <Badge variant={payment.isLate ? 'warning' : 'success'}>
                        {payment.isLate ? 'Late' : 'Paid'}
                      </Badge>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <Button 
                        size="sm" 
                        variant="outline" 
                        onClick={() => handleDownload(payment)}
                        className="inline-flex items-center gap-2"
                      >
                        <Download className="w-3 h-3" /> View Invoice
                      </Button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Login } from './pages/Login';
import { Layout } from './components/Layout';
import { LandlordDashboard } from './pages/landlord/LandlordDashboard';
import { Properties } from './pages/landlord/Properties';
import { PropertyDetails } from './pages/landlord/PropertyDetails';
import { Statistics } from './pages/landlord/Statistics';
import { LandlordComplaints } from './pages/landlord/LandlordComplaints';
import { PaymentHistory } from './pages/landlord/PaymentHistory';
import { TenantDashboard } from './pages/tenant/TenantDashboard';
import { CurrentRental } from './pages/tenant/CurrentRental';
import { Complaints } from './pages/tenant/Complaints';
import { Chatbot } from './components/Chatbot';
import { User, UserRole, Tenant, Property, Payment, PaymentStatus, Complaint } from './types';
import { MOCK_LANDLORD, MOCK_TENANT, PROPERTIES, MOCK_PAYMENTS } from './constants';
import { generateInvoicePDF } from './utils/invoiceGenerator';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [currentPage, setCurrentPage] = useState('dashboard');

  // App State (Hoisted for interactivity)
  const [properties, setProperties] = useState<Property[]>(PROPERTIES);
  const [payments, setPayments] = useState<Payment[]>(MOCK_PAYMENTS);
  const [currentTenant, setCurrentTenant] = useState<Tenant>(MOCK_TENANT);
  const [complaints, setComplaints] = useState<Complaint[]>([]);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);

  // Tenant Logic: Pay Rent
  const handlePayRent = (amount: number, method: string) => {
    // 1. Create new payment
    const newPayment: Payment = {
      id: `pay_${Date.now()}`,
      propertyId: currentTenant.currentPropertyId,
      tenantId: currentTenant.id,
      amount: amount,
      date: new Date().toISOString().split('T')[0],
      status: PaymentStatus.PAID,
      isLate: false,
      method: method
    };

    setPayments([newPayment, ...payments]);

    // 2. Update Credit Score (+15 points for demo effect)
    setCurrentTenant(prev => ({
      ...prev,
      creditScore: Math.min(900, prev.creditScore + 15)
    }));
  };

  const handleAddComplaint = (c: Omit<Complaint, 'id' | 'date' | 'status'>) => {
    const newComplaint: Complaint = {
      id: `comp_${Date.now()}`,
      date: new Date().toLocaleDateString(),
      status: 'Open',
      ...c
    };
    setComplaints([newComplaint, ...complaints]);
  };

  const handleResolveComplaint = (id: string) => {
    setComplaints(complaints.map(c => 
      c.id === id ? { ...c, status: 'Resolved' } : c
    ));
  };

  // Landlord Logic: View Property Details
  const handleSelectProperty = (id: string) => {
    setSelectedPropertyId(id);
    setCurrentPage('property-details');
  };

  const handleLogin = (role: UserRole) => {
    if (role === UserRole.LANDLORD) {
      setUser(MOCK_LANDLORD);
    } else {
      setUser(currentTenant);
    }
    setCurrentPage('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('dashboard');
    setSelectedPropertyId(null);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  // Get current tenant's property
  const tenantProperty = properties.find(p => p.id === currentTenant.currentPropertyId)!;

  // Prepare Context for AI
  const aiContext = user.role === UserRole.LANDLORD 
    ? { properties, recentRevenue: 9500, tenantIssues: complaints.length }
    : { tenantProfile: currentTenant, property: tenantProperty, paymentHistory: payments, activeComplaints: complaints };

  return (
    <Layout 
      user={user} 
      onLogout={handleLogout} 
      activePage={currentPage}
      onNavigate={setCurrentPage}
    >
      {/* Dynamic Page Rendering */}
      {user.role === UserRole.LANDLORD && (
        <>
          {currentPage === 'dashboard' && (
            <LandlordDashboard 
              properties={properties} 
              onNavigate={setCurrentPage} 
            />
          )}
          {currentPage === 'properties' && (
            <Properties 
              properties={properties} 
              onSelectProperty={handleSelectProperty} 
            />
          )}
          {currentPage === 'property-details' && selectedPropertyId && (
            <PropertyDetails 
              property={properties.find(p => p.id === selectedPropertyId)!}
              tenant={currentTenant.currentPropertyId === selectedPropertyId ? currentTenant : undefined}
              payments={payments}
              onBack={() => setCurrentPage('properties')}
            />
          )}
          {currentPage === 'statistics' && (
            <Statistics tenants={[currentTenant]} />
          )}
          {currentPage === 'landlord-complaints' && (
            <LandlordComplaints 
              complaints={complaints} 
              onResolve={handleResolveComplaint}
            />
          )}
          {currentPage === 'payment-history' && (
            <PaymentHistory 
              properties={properties} 
              payments={payments} 
              tenants={[currentTenant]} 
            />
          )}
        </>
      )}

      {user.role === UserRole.TENANT && (
        <>
          {currentPage === 'dashboard' && (
            <TenantDashboard 
              tenant={currentTenant}
              property={tenantProperty}
              payments={payments}
              onNavigate={setCurrentPage}
            />
          )}
          {currentPage === 'current-rental' && (
            <CurrentRental 
              tenant={currentTenant}
              property={tenantProperty}
              landlordName={MOCK_LANDLORD.name}
              onPayRent={handlePayRent}
            />
          )}
          {currentPage === 'complaints' && (
            <Complaints 
              complaints={complaints}
              onAddComplaint={handleAddComplaint}
            />
          )}
          {currentPage === 'payments' && (
            <div className="space-y-6">
              <h1 className="text-2xl font-bold text-gray-900">Full Payment History</h1>
              <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
                <table className="w-full text-left text-sm">
                  <thead className="bg-gray-50 border-b border-gray-100">
                    <tr>
                      <th className="px-6 py-4 font-medium text-gray-500">Date</th>
                      <th className="px-6 py-4 font-medium text-gray-500">Amount</th>
                      <th className="px-6 py-4 font-medium text-gray-500">Method</th>
                      <th className="px-6 py-4 font-medium text-gray-500 text-right">Receipt</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {payments.map((payment) => (
                      <tr key={payment.id} className="hover:bg-gray-50">
                        <td className="px-6 py-4 text-gray-900">{payment.date}</td>
                        <td className="px-6 py-4 font-medium">${payment.amount}</td>
                        <td className="px-6 py-4 text-gray-500">{payment.method || 'Bank Transfer'}</td>
                        <td className="px-6 py-4 text-right">
                          <button 
                            onClick={() => generateInvoicePDF(payment, tenantProperty, currentTenant)}
                            className="text-indigo-600 hover:text-indigo-800 font-medium"
                          >
                            Download PDF
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
           )}
        </>
      )}

      {/* AI Assistant */}
      <Chatbot userRole={user.role} contextData={aiContext} />
    </Layout>
  );
}

export default App;

import React from 'react';

// --- BUTTON ---
interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg font-medium transition-colors focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm",
    secondary: "bg-indigo-100 text-indigo-900 hover:bg-indigo-200",
    outline: "border border-gray-300 bg-white text-gray-700 hover:bg-gray-50",
    ghost: "text-gray-600 hover:bg-gray-100",
    danger: "bg-red-600 text-white hover:bg-red-700",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

// --- CARD ---
export const Card: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className = '', onClick }) => {
  return (
    <div 
